--liquibase formatted sql

--changeset hospital-service:095-doctor-chamber-time-real-seed
--comment: Seed doctor appointment_slots from DrChamberTime.xlsx (real chamber times)

UPDATE hospital.doctors
SET appointment_slots = NULL,
    updated_at = CURRENT_TIMESTAMP,
    updated_by = 'system-import'
WHERE created_by = 'system-import'
   OR doctor_code LIKE 'TEST-DOC-%';

